import{_ as e,o as l,c as a,ag as n}from"./chunks/framework.C9sp7nFj.js";const x=JSON.parse('{"title":"Landing Page","description":"","frontmatter":{},"headers":[],"relativePath":"regression/auth/landingPage.md","filePath":"regression/auth/landingPage.md"}'),d={name:"regression/auth/landingPage.md"};function i(r,t,s,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="landing-page" tabindex="-1">Landing Page <a class="header-anchor" href="#landing-page" aria-label="Permalink to &quot;Landing Page&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">QA 團隊與新人 Onboard 知識點</p><p><strong>模組業務目的：</strong> Landing Page 是非海外地區全新使用者進站的第一門面。測試重點在於確保品牌視覺、導流按鈕、客服管道以及行動裝置適配性（RWD）維持正常，避免因排版錯亂或按鈕失效導致潛在用戶流失。</p><p><strong>環境與注意事項：</strong></p><ol><li><strong>裝置驗證：</strong> 必須包含桌面端（Desktop）以及行動端（Mobile/RWD）的網頁排版檢查。</li><li><strong>狀態限制：</strong> 此頁面主要供「未登入」之訪客瀏覽，需驗證登入後的帳號不會被錯誤導回此頁。</li></ol></div><hr><h2 id="一、桌面端核心互動與導流-desktop-ui-interactivity" tabindex="-1">一、桌面端核心互動與導流 (Desktop UI &amp; Interactivity) <a class="header-anchor" href="#一、桌面端核心互動與導流-desktop-ui-interactivity" aria-label="Permalink to &quot;一、桌面端核心互動與導流 (Desktop UI &amp; Interactivity)&quot;">​</a></h2><h3 id="land-01-網頁視覺與文案排版檢查" tabindex="-1">[LAND-01] 網頁視覺與文案排版檢查 <a class="header-anchor" href="#land-01-網頁視覺與文案排版檢查" aria-label="Permalink to &quot;[LAND-01] 網頁視覺與文案排版檢查&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">狀態</th><th style="text-align:left;">測試步驟 (業務邏輯)</th><th style="text-align:left;">預期結果</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">1. 使用桌面端瀏覽器進入 Landing Page 首頁</td><td style="text-align:left;">網頁載入正常，無破圖，品牌文案字體與大小符合設計規範。</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">2. 檢視主視覺圖形與跑馬燈動態（若有）</td><td style="text-align:left;">動態效果流暢，無卡頓或元件重疊現象。</td></tr></tbody></table><h3 id="land-02-核心引流按鈕功能驗證" tabindex="-1">[LAND-02] 核心引流按鈕功能驗證 <a class="header-anchor" href="#land-02-核心引流按鈕功能驗證" aria-label="Permalink to &quot;[LAND-02] 核心引流按鈕功能驗證&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">狀態</th><th style="text-align:left;">測試步驟 (業務邏輯)</th><th style="text-align:left;">預期結果</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">1. 點擊頁面中央或導覽列的「帳號註冊/登入」按鈕</td><td style="text-align:left;">成功觸發並彈出登入/註冊視窗。</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">2. 點擊頁面中的「訪客進站 / Enter as guest」按鈕</td><td style="text-align:left;">成功建立訪客身分並直接導向主站大廳 (Explore Tab)。</td></tr></tbody></table><h3 id="land-03-輔助元件與客服通道" tabindex="-1">[LAND-03] 輔助元件與客服通道 <a class="header-anchor" href="#land-03-輔助元件與客服通道" aria-label="Permalink to &quot;[LAND-03] 輔助元件與客服通道&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">狀態</th><th style="text-align:left;">測試步驟 (業務邏輯)</th><th style="text-align:left;">預期結果</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">1. 將網頁向下捲動至超過一頁的高度</td><td style="text-align:left;">頁面右下角（或指定位置）成功出現「回到頂部 / Go to top」按鈕。</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">2. 點擊「回到頂部 / Go to top」按鈕</td><td style="text-align:left;">網頁視窗流暢捲動回最上方，且該按鈕隨之消失。</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">3. 點擊頁面上的「線上客服 / Customer Help」按鈕</td><td style="text-align:left;">成功叫出線上客服系統（如 Zendesk/Intercom 彈窗）或正確導向幫助中心網頁。</td></tr></tbody></table><hr><h2 id="二、行動端響應式設計驗證-mobile-rwd" tabindex="-1">二、行動端響應式設計驗證 (Mobile RWD) <a class="header-anchor" href="#二、行動端響應式設計驗證-mobile-rwd" aria-label="Permalink to &quot;二、行動端響應式設計驗證 (Mobile RWD)&quot;">​</a></h2><h3 id="land-04-行動裝置排版與斷字檢查" tabindex="-1">[LAND-04] 行動裝置排版與斷字檢查 <a class="header-anchor" href="#land-04-行動裝置排版與斷字檢查" aria-label="Permalink to &quot;[LAND-04] 行動裝置排版與斷字檢查&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">狀態</th><th style="text-align:left;">測試步驟 (業務邏輯)</th><th style="text-align:left;">預期結果</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">1. 使用手機瀏覽器，或使用電腦瀏覽器開發者工具切換至手機模式（如 iPhone 視窗）</td><td style="text-align:left;">網頁排版自動重組，元件寬度 100% 適配手機螢幕。</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">2. 檢查圖片與文字區塊</td><td style="text-align:left;">1. 所有文字無超出螢幕邊界（無水平捲軸）。<br>2. 圖片無變形、無等比例壓縮失真或破圖。</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">3. 滑動檢視整個頁面</td><td style="text-align:left;">捲動滑暢，無垂直方向的空白卡死區塊。</td></tr></tbody></table><h3 id="land-05-行動端專屬選單與按鈕點擊熱區" tabindex="-1">[LAND-05] 行動端專屬選單與按鈕點擊熱區 <a class="header-anchor" href="#land-05-行動端專屬選單與按鈕點擊熱區" aria-label="Permalink to &quot;[LAND-05] 行動端專屬選單與按鈕點擊熱區&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">狀態</th><th style="text-align:left;">測試步驟 (業務邏輯)</th><th style="text-align:left;">預期結果</th></tr></thead><tbody><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">1. 檢查導覽列是否收合為漢堡選單（Hamburger Menu）</td><td style="text-align:left;">原本桌面端的橫向選單成功收合。</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">2. 點擊漢堡選單圖示</td><td style="text-align:left;">選單順利展開，且點擊熱區大小適中，不會誤觸其他元件。</td></tr><tr><td style="text-align:center;"><input type="checkbox"></td><td style="text-align:left;">3. 於展開的選單中點擊任一跳轉連結</td><td style="text-align:left;">正確導向目標頁面，且選單自動關閉。</td></tr></tbody></table>',16)])])}const y=e(d,[["render",i]]);export{x as __pageData,y as default};
